export const mergeDuplicates = mutation({
  args: { orgId: v.string() },
  handler: async (ctx, { orgId }) => {
    const allProducts = await ctx.db.query("products")
      .withIndex("by_orgId", (q) => q.eq("orgId", orgId))
      .collect();

    // Match any of these continuation suffixes (case-insensitive)
    const contSuffixes = [" - cont", " - continued", " continued", / cont - pg\d+.*$/i, / continued p\d+.*$/i];
    const stripSuffix = (title: string) => {
      for (const s of contSuffixes) {
        if (typeof s === "string" && title.toLowerCase().endsWith(s.toLowerCase()))
          return title.slice(0, title.length - s.length).trim();
        if (s instanceof RegExp) {
          const m = title.match(s);
          if (m) return title.slice(0, m.index).trim();
        }
      }
      return null;
    };

    const contProducts = allProducts.filter(p => stripSuffix(p.title) !== null);
    let merged = 0, deleted = 0, entriesMoved = 0;

    for (const cont of contProducts) {
      const baseName = stripSuffix(cont.title)!;
      const base = allProducts.find(p => p.title === baseName);

      const entries = await ctx.db.query("stockBookEntries")
        .withIndex("by_orgId_product", (q) => q.eq("orgId", orgId).eq("productId", cont._id))
        .collect();

      if (base) {
        // Merge entries and opening stock into base
        for (const e of entries) { await ctx.db.patch(e._id, { productId: base._id }); entriesMoved++; }
        await ctx.db.patch(base._id, { openingStock: base.openingStock + cont.openingStock });
        await ctx.db.delete(cont._id);
        merged++;
      } else {
        // Orphan cont — delete entries and product (no base to merge into)
        for (const e of entries) { await ctx.db.delete(e._id); }
        await ctx.db.delete(cont._id);
        deleted++;
      }
    }
    return { merged, deleted, entriesMoved };
  },
})